import { mkdir, writeFile } from "node:fs/promises";
import path from "node:path";

const username = process.env.GITHUB_REPOSITORY_OWNER || "insistanan";
const token = process.env.GITHUB_TOKEN;
const outDir = process.env.OUTPUT_DIR || "dist";

if (!token) {
  throw new Error("GITHUB_TOKEN is required");
}

const apiHeaders = {
  Accept: "application/vnd.github+json",
  Authorization: `Bearer ${token}`,
  "X-GitHub-Api-Version": "2022-11-28",
  "User-Agent": "profile-readme-static-stats",
};

async function githubJson(url) {
  const endpoint = url.startsWith("https://")
    ? url
    : `https://api.github.com${url}`;
  const response = await fetch(endpoint, { headers: apiHeaders });

  if (!response.ok) {
    const body = await response.text();
    throw new Error(`${response.status} ${response.statusText}: ${body}`);
  }

  return response.json();
}

async function githubGraphql(query, variables) {
  const response = await fetch("https://api.github.com/graphql", {
    method: "POST",
    headers: {
      ...apiHeaders,
      "Content-Type": "application/json",
    },
    body: JSON.stringify({ query, variables }),
  });

  const payload = await response.json();

  if (!response.ok || payload.errors) {
    throw new Error(
      JSON.stringify(payload.errors || payload, null, 2)
    );
  }

  return payload.data;
}

async function getAllOwnerRepos(login) {
  const repos = [];

  for (let page = 1; ; page += 1) {
    const batch = await githubJson(
      `/users/${encodeURIComponent(login)}/repos?type=owner&sort=updated&per_page=100&page=${page}`
    );

    if (batch.length === 0) {
      break;
    }

    repos.push(...batch.filter((repo) => !repo.fork));
  }

  return repos;
}

async function mapLimit(items, limit, task) {
  const results = [];
  let cursor = 0;

  async function worker() {
    for (;;) {
      const index = cursor;
      cursor += 1;

      if (index >= items.length) {
        return;
      }

      results[index] = await task(items[index], index);
    }
  }

  await Promise.all(
    Array.from({ length: Math.min(limit, items.length) }, () => worker())
  );

  return results;
}

async function getContributionCount(login) {
  const now = new Date();
  const from = new Date(Date.UTC(now.getUTCFullYear(), 0, 1)).toISOString();

  try {
    const data = await githubGraphql(
      `
        query($login: String!, $from: DateTime!, $to: DateTime!) {
          user(login: $login) {
            contributionsCollection(from: $from, to: $to) {
              contributionCalendar {
                totalContributions
              }
            }
          }
        }
      `,
      { login, from, to: now.toISOString() }
    );

    return (
      data.user?.contributionsCollection?.contributionCalendar
        ?.totalContributions ?? 0
    );
  } catch (error) {
    console.warn(`Could not read contribution count: ${error.message}`);
    return 0;
  }
}

async function collectLanguageTotals(repos) {
  const totals = new Map();

  await mapLimit(repos, 8, async (repo) => {
    const languages = await githubJson(repo.languages_url);

    for (const [name, bytes] of Object.entries(languages)) {
      totals.set(name, (totals.get(name) || 0) + bytes);
    }
  });

  return [...totals.entries()]
    .map(([name, bytes]) => ({
      name,
      bytes,
      color: languageColors[name] || "#858585",
    }))
    .sort((a, b) => b.bytes - a.bytes);
}

function escapeXml(value) {
  return String(value)
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;");
}

function formatNumber(value) {
  if (value >= 1_000_000) {
    return `${(value / 1_000_000).toFixed(1)}M`;
  }

  if (value >= 1_000) {
    return `${(value / 1_000).toFixed(1)}k`;
  }

  return String(value);
}

function renderStatsCard({ user, repos, totalStars, totalForks, contributions }) {
  const rows = [
    ["Total Stars Earned", totalStars],
    ["Total Forks", totalForks],
    ["Contributions This Year", contributions],
    ["Own Public Repos", repos.length],
    ["Followers", user.followers],
  ];

  const rowSvg = rows
    .map(([label, value], index) => {
      const y = 69 + index * 24;

      return `
        <text x="34" y="${y}" class="label">${escapeXml(label)}</text>
        <text x="458" y="${y}" class="value" text-anchor="end">${formatNumber(value)}</text>`;
    })
    .join("");

  return `<?xml version="1.0" encoding="UTF-8"?>
<svg width="495" height="195" viewBox="0 0 495 195" fill="none" xmlns="http://www.w3.org/2000/svg" role="img" aria-labelledby="title desc">
  <title id="title">${escapeXml(username)} GitHub Stats</title>
  <desc id="desc">Static GitHub profile statistics generated by GitHub Actions.</desc>
  <style>
    .title { fill: #70a5fd; font: 600 19px -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif; }
    .label { fill: #c3c6d1; font: 500 14px -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif; }
    .value { fill: #38bdae; font: 700 14px -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif; }
  </style>
  <rect width="495" height="195" rx="6" fill="#1a1b27"/>
  <rect x="1" y="1" width="493" height="193" rx="5" stroke="#2f334d" stroke-width="1"/>
  <text x="24" y="36" class="title">${escapeXml(username)}'s GitHub Stats</text>
  ${rowSvg}
</svg>
`;
}

function renderTopLanguagesCard(languages) {
  const topLanguages = languages.slice(0, 6);
  const totalBytes = languages.reduce((sum, item) => sum + item.bytes, 0);

  const barWidth = 445;
  let offset = 0;
  const barSegments = topLanguages
    .map((language) => {
      const width =
        totalBytes === 0 ? 0 : Math.max(2, (language.bytes / totalBytes) * barWidth);
      const segment = `<rect x="${25 + offset}" y="58" width="${width.toFixed(
        2
      )}" height="10" fill="${language.color}"/>`;
      offset += width;
      return segment;
    })
    .join("");

  const languageRows =
    topLanguages.length === 0
      ? `<text x="25" y="95" class="label">No language data yet</text>`
      : topLanguages
          .map((language, index) => {
            const percent =
              totalBytes === 0 ? 0 : (language.bytes / totalBytes) * 100;
            const colX = index % 2 === 0 ? 25 : 260;
            const y = 95 + Math.floor(index / 2) * 32;

            return `
              <circle cx="${colX + 6}" cy="${y - 5}" r="6" fill="${language.color}"/>
              <text x="${colX + 20}" y="${y}" class="label">${escapeXml(language.name)}</text>
              <text x="${colX + 205}" y="${y}" class="value" text-anchor="end">${percent.toFixed(1)}%</text>`;
          })
          .join("");

  return `<?xml version="1.0" encoding="UTF-8"?>
<svg width="495" height="195" viewBox="0 0 495 195" fill="none" xmlns="http://www.w3.org/2000/svg" role="img" aria-labelledby="title desc">
  <title id="title">${escapeXml(username)} Top Languages</title>
  <desc id="desc">Static top languages card generated by GitHub Actions.</desc>
  <style>
    .title { fill: #70a5fd; font: 600 19px -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif; }
    .label { fill: #c3c6d1; font: 500 13px -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif; }
    .value { fill: #38bdae; font: 700 13px -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif; }
  </style>
  <rect width="495" height="195" rx="6" fill="#1a1b27"/>
  <rect x="1" y="1" width="493" height="193" rx="5" stroke="#2f334d" stroke-width="1"/>
  <text x="24" y="36" class="title">Top Languages</text>
  <clipPath id="barClip"><rect x="25" y="58" width="445" height="10" rx="5"/></clipPath>
  <rect x="25" y="58" width="445" height="10" rx="5" fill="#2f334d"/>
  <g clip-path="url(#barClip)">${barSegments}</g>
  ${languageRows}
</svg>
`;
}

const languageColors = {
  JavaScript: "#f1e05a",
  TypeScript: "#3178c6",
  Python: "#3572A5",
  Java: "#b07219",
  HTML: "#e34c26",
  CSS: "#563d7c",
  Vue: "#41b883",
  Go: "#00ADD8",
  Rust: "#dea584",
  "C++": "#f34b7d",
  C: "#555555",
  "C#": "#178600",
  PHP: "#4F5D95",
  Shell: "#89e051",
  PowerShell: "#012456",
  Kotlin: "#A97BFF",
  Swift: "#F05138",
  Ruby: "#701516",
  Dart: "#00B4AB",
  Svelte: "#ff3e00",
  Astro: "#ff5d01",
};

const user = await githubJson(`/users/${encodeURIComponent(username)}`);
const repos = await getAllOwnerRepos(username);
const contributions = await getContributionCount(username);
const totalStars = repos.reduce((sum, repo) => sum + repo.stargazers_count, 0);
const totalForks = repos.reduce((sum, repo) => sum + repo.forks_count, 0);
const languages = await collectLanguageTotals(repos);

await mkdir(outDir, { recursive: true });
await writeFile(
  path.join(outDir, "github-stats.svg"),
  renderStatsCard({ user, repos, totalStars, totalForks, contributions })
);
await writeFile(path.join(outDir, "top-langs.svg"), renderTopLanguagesCard(languages));

console.log(`Generated static cards for ${username}`);
